public String getFieldValue(APIEntry e, int domainId) {
    return _getFieldValue(e, false, domainId, -1, -1);
}

public String getSubtableFieldValue(APIEntry e, int subtableKey, int rowNum, int domainId) {
    return _getFieldValue(e, true, domainId, subtableKey, rowNum);
}

private String _getFieldValue(APIEntry e, boolean isSubtableField, int domainId, int subtableKey, int rowNum) {
    String fieldValue;
    if (isSubtableField) fieldValue = e.getSubtableFieldValue(subtableKey, rowNum, "" + domainId);
    else fieldValue = e.getFieldValue(domainId);

    if (fieldValue == null) return "&nbsp;";
    
    String displayValue = fieldValue;
    CellInfo info = fields.get(domainId);
    
    if (info.getAttribute("fmt_n") != null) {
        String format = Encoder.unformatNUIAttr(info.getAttribute("fmt_n"));
        
        displayValue = Encoder.formatNumber(fieldValue, format);
    }
    else if (info.getAttribute("fmt_d") != null) {
        String dateFormat = info.getAttribute("fmt_d");
        
        SimpleDateFormat sdf;
        try {
            sdf = new SimpleDateFormat(dateFormat);
        }
        catch (Exception ex){
            sdf = new SimpleDateFormat("yyyy/MM/dd");
        }
        try {
            Date parsedDate = Encoder.parseDateStrict(fieldValue, dateFormat);
            if (parsedDate == null) parsedDate = Encoder.parseStandardDate(fieldValue);
            if (parsedDate == null) parsedDate = Encoder.parseDate(fieldValue);
            if (parsedDate != null) displayValue = sdf.format(parsedDate);
            else displayValue = fieldValue;
        } catch (Exception e1) {
            displayValue = fieldValue;
        }
        
    }
    
    if (displayValue.equals("")) displayValue = "&nbsp;";
    
    return displayValue;
}

private String getFieldValues(APIEntry e, int domainId) {
    List<String> values = e.getFieldValues(domainId);
    String displayValue = "";
    if (values == null) return displayValue;
    List<String> lov = Account.getInstance(apname).getLOV(domainId);
    displayValue = reorderContent(values, lov);
    return displayValue;
}

private String getSubtableFieldValues(APIEntry e, int subtableKey, int rowNum, int domainId) {
    List<String> values = e.getSubtableFieldValues(subtableKey, rowNum, "" + domainId);
    String displayValue = "";
    if (values == null) return displayValue;
    List<String> lov = Account.getInstance(apname).getLOV(domainId);
    displayValue = reorderContent(values, lov);
    return displayValue;
}

private String reorderContent(List<String> content, List<String> lov) {
    if(content == null) return "";
    if(lov == null) return content.toString();
    String result = "";
    for (String v : lov) {
        if(v == null) continue;
        for (String s : content) {
            if(s != null && s.equals(v)) {
                if (result.length() > 0) result += ", ";
                result += s;
                break;
            }
        }
    }
    for (String s : content){
        if (s == null) continue;
        if (!lov.contains(s)) {
            if (result.length() > 0) result += ", ";
            result += s;
        }
    }
    return result;
}
       
